     1→/*
     2→ * atanh() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly atanh  (test_atanh_opt.elf)
     6→ *   2. Linked with toolchain's default atanh       (test_atanh_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→#ifdef EN_PERF
    16→#define PF_COUNTER
    17→#include "nds_pfcounter.h"
    18→#endif
    19→
    20→static inline uint64_t d2u(double d)
    21→{
    22→    union { double d; uint64_t u; } x;
    23→    x.d = d;
    24→    return x.u;
    25→}
    26→
    27→static inline double u2d(uint64_t u)
    28→{
    29→    union { double d; uint64_t u; } x;
    30→    x.u = u;
    31→    return x.d;
    32→}
    33→
    34→static volatile double g_acc;
    35→
    36→static void emit(double x)
    37→{
    38→#ifdef EN_PERF
    39→    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    40→    g_acc += atanh(vx);
    41→#else
    42→    double r = atanh(x);
    43→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    44→#endif
    45→}
    46→
    47→static void emit_u(uint64_t bits)
    48→{
    49→    emit(u2d(bits));
    50→}
    51→
    52→/* ------------------------------------------------------------------ */
    53→/* test_representative_100: 100 representative inputs for atanh        */
    54→/* atanh domain: (-1, 1); poles at +-1; atanh(x) ~ x for small x      */
    55→/* ------------------------------------------------------------------ */
    56→
    57→static void test_representative_100(void)
    58→{
    59→    /* --- Section 1: Special IEEE 754 values (7) --- */
    60→    emit(0.0);
    61→    emit(-0.0);
    62→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    63→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    64→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    65→    emit_u(0x7ff0000000000000ULL);  /* +Inf (out of domain) */
    66→    emit_u(0xfff0000000000000ULL);  /* -Inf (out of domain) */
    67→
    68→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    69→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    70→    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    71→    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    72→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    73→    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    74→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    75→
    76→    /* --- Section 3: Normal boundaries and out-of-domain values (6) --- */
    77→    emit(DBL_MIN);                  /* smallest normal: 2^-1022 */
    78→    emit(-DBL_MIN);
    79→    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    80→    emit(2.0);                      /* outside domain: |x| > 1 -> NaN */
    81→    emit(-2.0);                     /* outside domain */
    82→    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: far outside domain */
    83→
    84→    /* --- Section 4: ULP neighbors of +1.0 (the positive pole) (9) --- */
    85→    emit_u(0x3fefffffffffffffULL);  /* 1.0 - 1 ULP: just inside domain */
    86→    emit_u(0x3feffffffffffffeULL);  /* 1.0 - 2 ULP */
    87→    emit_u(0x3feffffffffffffdULL);  /* 1.0 - 3 ULP */
    88→    emit(1.0);                      /* exactly +1.0: pole -> +Inf */
    89→    emit_u(0x3ff0000000000001ULL);  /* 1.0 + 1 ULP: outside domain -> NaN */
    90→    emit_u(0x3ff0000000000002ULL);  /* 1.0 + 2 ULP: outside domain */
    91→    emit_u(0x3ff0000000000010ULL);  /* 1.0 + several ULP */
    92→    emit_u(0x3ff0000000000100ULL);  /* 1.0 + many ULP */
    93→    emit_u(0x3ff0000000001000ULL);  /* moderately above 1.0 */
    94→
    95→    /* --- Section 5: ULP neighbors of -1.0 (the negative pole) (6) --- */
    96→    emit_u(0xbfefffffffffffffULL);  /* -1.0 + 1 ULP: just inside domain */
    97→    emit_u(0xbfeffffffffffffeULL);  /* -1.0 + 2 ULP */
    98→    emit(-1.0);                     /* exactly -1.0: pole -> -Inf */
    99→    emit_u(0xbff0000000000001ULL);  /* -1.0 - 1 ULP: outside domain */
   100→    emit_u(0xbff0000000000002ULL);  /* -1.0 - 2 ULP: outside domain */
   101→    emit(-1.5);                     /* clearly outside domain */
   102→
   103→    /* --- Section 6: Uniformly spaced values across domain (14) --- */
   104→    emit(0.1);
   105→    emit(-0.1);
   106→    emit(0.2);
   107→    emit(-0.2);
   108→    emit(0.3);
   109→    emit(-0.3);
   110→    emit(0.4);
   111→    emit(-0.4);
   112→    emit(0.6);
   113→    emit(-0.6);
   114→    emit(0.7);
   115→    emit(-0.7);
   116→    emit(0.8);
   117→    emit(-0.8);
   118→
   119→    /* --- Section 7: Near-zero fast-path boundaries (8) --- */
   120→    /* atanh(x) ~ x for tiny x; implementations often have a threshold */
   121→    emit_u(0x3cb0000000000000ULL);  /* 2^-52: one ULP of 1.0, near identity threshold */
   122→    emit_u(0xbcb0000000000000ULL);  /* -2^-52 */
   123→    emit_u(0x3e50000000000000ULL);  /* 2^-26: typical Taylor-series threshold */
   124→    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
   125→    emit_u(0x3f20000000000000ULL);  /* 2^-13 */
   126→    emit_u(0xbf20000000000000ULL);  /* -2^-13 */
   127→    emit_u(0x3f80000000000000ULL);  /* 2^-7 = 0.0078125 */
   128→    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
   129→
   130→    /* --- Section 8: ULP neighbors of 0.5 (polynomial switch point) (9) --- */
   131→    /* Many atanh implementations use different polynomials for |x| < 0.5 */
   132→    emit_u(0x3fdffffffffffffeULL);  /* 0.5 - 2 ULP */
   133→    emit_u(0x3fdfffffffffffffULL);  /* 0.5 - 1 ULP */
   134→    emit(0.5);                      /* exactly 0.5: atanh(0.5) = ln(3)/2 ~ 0.5493 */
   135→    emit_u(0x3fe0000000000001ULL);  /* 0.5 + 1 ULP */
   136→    emit_u(0x3fe0000000000002ULL);  /* 0.5 + 2 ULP */
   137→    emit_u(0xbfdffffffffffffeULL);  /* -0.5 - 2 ULP (toward zero) */
   138→    emit_u(0xbfdfffffffffffffULL);  /* -0.5 - 1 ULP */
   139→    emit(-0.5);                     /* exactly -0.5 */
   140→    emit_u(0xbfe0000000000001ULL);  /* -0.5 + 1 ULP (away from zero) */
   141→
   142→    /* --- Section 9: Critical pole-approach region (12) --- */
   143→    /* Values very close to +-1 where log(1-x^2) loses precision */
   144→    emit(0.9);
   145→    emit(-0.9);
   146→    emit(0.99);
   147→    emit(-0.99);
   148→    emit(0.999);
   149→    emit(-0.999);
   150→    emit(0.9999);
   151→    emit(-0.9999);
   152→    emit(0.99999);
   153→    emit(-0.99999);
   154→    emit(0.999999);
   155→    emit(-0.999999);
   156→
   157→    /* --- Section 10: ULP triplets and stress bit patterns (23) --- */
   158→    /* ULP triplet near 0.25 */
   159→    emit_u(0x3fcfffffffffffffULL);  /* 0.25 - 1 ULP */
   160→    emit(0.25);                     /* exactly 0.25 */
   161→    emit_u(0x3fd0000000000001ULL);  /* 0.25 + 1 ULP */
   162→
   163→    /* ULP triplet near 0.75 */
   164→    emit_u(0x3fe7ffffffffffffULL);  /* 0.75 - 1 ULP */
   165→    emit(0.75);                     /* exactly 0.75 */
   166→    emit_u(0x3fe8000000000001ULL);  /* 0.75 + 1 ULP */
   167→
   168→    /* ULP triplet near sqrt(2)/2 ~ 0.7071 (common test value for inverse trig) */
   169→    emit_u(0x3fe6a09e667f3bccULL);  /* sqrt(2)/2 - 1 ULP */
   170→    emit_u(0x3fe6a09e667f3bcdULL);  /* sqrt(2)/2 */
   171→    emit_u(0x3fe6a09e667f3bceULL);  /* sqrt(2)/2 + 1 ULP */
   172→
   173→    /* ULP triplet near sqrt(3)/2 ~ 0.8660 */
   174→    emit_u(0x3febb67ae8584caaULL);  /* sqrt(3)/2 - 1 ULP */
   175→    emit_u(0x3febb67ae8584cabULL);  /* sqrt(3)/2 */
   176→    emit_u(0x3febb67ae8584cacULL);  /* sqrt(3)/2 + 1 ULP */
   177→
   178→    /* Special bit patterns within domain */
   179→    emit_u(0x3fe921fb54442d18ULL);  /* pi/4 ~ 0.7854: within domain */
   180→    emit_u(0x3fd921fb54442d18ULL);  /* pi/8 ~ 0.3927: within domain */
   181→    emit_u(0xbfe921fb54442d18ULL);  /* -pi/4 */
   182→    emit_u(0xbfd921fb54442d18ULL);  /* -pi/8 */
   183→
   184→    /* Additional rational fractions */
   185→    emit(0.125);                    /* 1/8 */
   186→    emit(-0.125);
   187→    emit(0.375);                    /* 3/8 */
   188→    emit(-0.375);
   189→    emit(0.625);                    /* 5/8 */
   190→    emit(-0.625);
   191→    emit(0.875);                    /* 7/8 */
   192→}
   193→
   194→#ifndef EN_PERF
   195→/* 7. Sweep [-0.99, 0.99] in 200 steps */
   196→static void test_sweep(void)
   197→{
   198→    double lo = -0.99;
   199→    double hi = 0.99;
   200→    int nsteps = 200;
   201→    double step = (hi - lo) / (double)nsteps;
   202→
   203→    for (int i = 0; i <= nsteps; i++)
   204→        emit(lo + (double)i * step);
   205→}
   206→
   207→/* 8. Sample [0, 0.5] every 4194304 ULP (~250 cases) */
   208→static void test_exhaustive_small(void)
   209→{
   210→    static const uint64_t vals[] = {
   211→        0x0000000000000000ULL, /* 0.0 */
   212→        0x3fb0000000000000ULL, /* 0.0625 */
   213→        0x3fc0000000000000ULL, /* 0.125 */
   214→        0x3fd0000000000000ULL, /* 0.25 */
   215→        0x3fd8000000000000ULL, /* 0.375 */
   216→        0x3fe0000000000000ULL, /* 0.5 */
   217→    };
   218→    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
   219→        emit_u(vals[i]);
   220→}
   221→#endif
   222→
   223→/* ------------------------------------------------------------------ */
   224→
   225→int main(void)
   226→{
   227→#ifdef EN_PERF
   228→    startPFM;
   229→    test_representative_100();
   230→    stopPFM;
   231→    readResult();
   232→    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
   233→#else
   234→    test_representative_100();
   235→    test_sweep();
   236→    test_exhaustive_small();
   237→#endif
   238→    return 0;
   239→}
